feedbackvariables.text:
/* First parse the input string, depending on what it is we can get a list, a stackmap, an integer, a float, a string or und if nothing is found. */
parsed: stackjson_parse(ans1);
/* As we will most likely get an list of stackmaps we can just split that list based on which of the elements have which colors like this. We may get und, do try to figure out why and when. */
red:if is(parsed=und) then 0 else length(sublist(parsed, lambda([x], stackmap_get(x,"color")="red")));
green:if is(parsed=und) then 0 else length(sublist(parsed, lambda([x], stackmap_get(x,"color")="green")));
blue:if is(parsed=und) then 0 else length(sublist(parsed, lambda([x], stackmap_get(x,"color")="blue")));
black:if is(parsed=und) then 0 else length(sublist(parsed, lambda([x], stackmap_get(x,"color")="black")));
/* As an exercise you might want to evaluate the means of coordinates of each color group and draw a suitable picture in the feedback... note however that feedback plots cannot reference inputs. */

/* STACK can also output JSON if need be and stackmap objects can be used in other places too, but are very inconvenient when dealing with modifications to deep structures. To find out more about what is available just check the "stackstrings.mac" file it defines the functions. */

questionvariables.text:
/* Atomic Structure Explorer - JSXGraph slider activity */

atom_cases:[
  ["Carbon", "C", 6, 14],
  ["Oxygen", "O", 8, 16],
  ["Nitrogen", "N", 7, 15],
  ["Sodium", "Na", 11, 23],
  ["Magnesium", "Mg", 12, 24],
  ["Aluminium", "Al", 13, 27],
  ["Chlorine", "Cl", 17, 35]
];

atom_index: rand(length(atom_cases))+1;

atom_name: atom_cases[atom_index][1];
atom_symbol: atom_cases[atom_index][2];
atomic_number: atom_cases[atom_index][3];
mass_number: atom_cases[atom_index][4];

target_protons: atomic_number;
target_neutrons: mass_number - atomic_number;
target_electrons: atomic_number;

/* Starting values deliberately different from the target. */
start_protons: rand_with_prohib(1,18,[target_protons]);
start_neutrons: rand_with_prohib(0,22,[target_neutrons]);
start_electrons: rand_with_prohib(1,18,[target_electrons]);

/* Teacher answers */
ta1: target_protons;
ta2: target_neutrons;
ta3: target_electrons;

feedbackvariables.text:
p_student: round(ans1);
n_student: round(ans2);
e_student: round(ans3);

p_ok: is(p_student = ta1);
n_ok: is(n_student = ta2);
e_ok: is(e_student = ta3);

atom_ok: if p_ok and n_ok and e_ok then 1 else 0;

/* No need to care about the shape of the answer here, the validators ensure that
 * at this point ans1 is what we expect.
 */
[nodes,edges]:args(ans1);
N:length(nodes);
adj_matrix:dgo_to_adj_matrix(ans1);

/* Now we will see if we can find the connections we expect from the matrix. 
 * Note that for the first two to function we needed to forbid self-loops. 
 */

/* Those that fulfill constraint 1. */
c1: sublist_indices(colsum(adj_matrix), lambda([x],ev(is(x=N-1),simp)));

/* Those that fulfill constraint 2. To understand this understand what `powerset` does. */
c2: subset(powerset(setify(makelist(x,x,1,N)),3), lambda([x],block([indices,simp,tmp],
 simp:true,
 indices:listify(x),
 tmp:matrix([adj_matrix[indices[1],indices[1]], adj_matrix[indices[1],indices[2]] , adj_matrix[indices[1],indices[3]]],
            [adj_matrix[indices[2],indices[1]], adj_matrix[indices[2],indices[2]] , adj_matrix[indices[2],indices[3]]],
            [adj_matrix[indices[3],indices[1]], adj_matrix[indices[3],indices[2]] , adj_matrix[indices[3],indices[3]]]),
 is(tmp=matrix([0,1,1],[1,0,1],[1,1,0]))
))
);

/* Those that fulfill constraint 3. */
c3: sublist_indices(colsum(adj_matrix), lambda([x],ev(is(x=0),simp)));

questionvariables.text:
slope: rand([1/2, 3/2, 2]);
intercept: rand_with_step(-3, -1, 1);
expr: slope*x + intercept;  /* our function f(x) */
ta1: [2, 2 * float(slope)];  /* A correct answer for A with integer coordinates */

xA_init: 1 + rand(3);
yA_init: -1 - rand(3);
A_init: [xA_init, yA_init];  /* Initial position of A */

slope: rand([1/2, 3/2, 2]);
intercept: rand_with_step(-3, -1, 1);
expr: slope*x + intercept;  /* our function f(x) */
ta1: [2, 2 * float(slope)];  /* A correct answer for A with integer coordinates */

xA_init: 1 + rand(3);
yA_init: -1 - rand(3);
A_init: [xA_init, yA_init];  /* Initial position of A */
